import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import { toast, ToastContainer } from 'react-toastify';
import 'react-toastify/dist/ReactToastify.css';

const Register = () => {
  const [formData, setFormData] = useState({
    Username: '',
    Password: '',
    ClientCode: ''
  });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const validatePassword = (password) => {
    const errors = [];
    if (!/[A-Z]/.test(password)) {
      errors.push("Password must have at least one uppercase letter ('A'-'Z')");
    }
    if (!/[0-9]/.test(password)) {
      errors.push("Password must have at least one digit ('0'-'9')");
    }
    if (!/[^A-Za-z0-9]/.test(password)) {
      errors.push("Password must have at least one non-alphanumeric character");
    }
    return errors;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    const passwordErrors = validatePassword(formData.Password);
    if (passwordErrors.length > 0) {
      setError(passwordErrors.join('\n'));
      setLoading(false);
      return;
    }
    try {
      await axios.post('https://soni.loyalstring.co.in/api/ProductMaster/AuthRegister', formData);
      toast.success('Registration successful! Please login.', {
        position: "top-right",
        autoClose: 3000,
        theme: "colored"
      });
      navigate('/login');
    } catch (err) {
      const errorMessage = err.response?.data || 'Registration failed. Please try again.';
      setError(Array.isArray(errorMessage) ? errorMessage.map(e => e.Description).join('\n') : errorMessage);
      toast.error('Registration failed. Please check the requirements.', {
        position: "top-right",
        autoClose: 3000,
        theme: "colored"
      });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{
      minHeight: '100vh',
      background: '#f6f7fb',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      fontFamily: 'Poppins, Montserrat, Arial, sans-serif'
    }}>
      <ToastContainer />
      <div style={{
        minWidth: 350,
        maxWidth: 370,
        width: '100%',
        background: '#fff',
        borderRadius: 16,
        boxShadow: '0 8px 32px 0 rgba(60,60,100,0.10)',
        padding: '2.5rem 2rem',
        margin: '2rem 0'
      }}>
        <div className="text-center mb-3">
          <h2 className="fw-bold mb-1" style={{ fontSize: '1.5rem', color: '#222', letterSpacing: 0.5 }}>RFID API</h2>
          <div className="mb-2 text-primary fw-semibold" style={{ fontSize: '1.08rem', letterSpacing: 0.5 }}>Loyalstring Pvt Ltd</div>
          <div className="text-muted mb-2" style={{ fontSize: '0.97rem' }}>Register to access the RFID API Dashboard</div>
        </div>
        {error && (
          <div className="alert alert-danger py-2" style={{ fontSize: '0.98rem' }}>{error}</div>
        )}
        <form onSubmit={handleSubmit} autoComplete="off">
          <div className="mb-3">
            <label htmlFor="Username" className="form-label" style={{ fontWeight: 500, color: '#222' }}>Username</label>
            <input
              type="text"
              className="form-control"
              id="Username"
              name="Username"
              value={formData.Username}
              onChange={handleChange}
              required
              placeholder="Enter your email or username"
              style={{ fontSize: '1.05rem', background: '#f6f7fb', border: '1px solid #e0e0e0', borderRadius: 8 }}
            />
          </div>
          <div className="mb-3">
            <label htmlFor="ClientCode" className="form-label" style={{ fontWeight: 500, color: '#222' }}>Client Code</label>
            <input
              type="text"
              className="form-control"
              id="ClientCode"
              name="ClientCode"
              value={formData.ClientCode}
              onChange={handleChange}
              required
              placeholder="Enter your client code"
              style={{ fontSize: '1.05rem', background: '#f6f7fb', border: '1px solid #e0e0e0', borderRadius: 8 }}
            />
          </div>
          <div className="mb-3">
            <label htmlFor="Password" className="form-label" style={{ fontWeight: 500, color: '#222' }}>Password</label>
            <input
              type="password"
              className="form-control"
              id="Password"
              name="Password"
              value={formData.Password}
              onChange={handleChange}
              required
              placeholder="Create a strong password"
              style={{ fontSize: '1.05rem', background: '#f6f7fb', border: '1px solid #e0e0e0', borderRadius: 8 }}
            />
            <small className="text-muted">
              Password must contain:
              <ul className="mb-0">
                <li>At least one uppercase letter</li>
                <li>At least one number</li>
                <li>At least one special character</li>
              </ul>
            </small>
          </div>
          <button
            type="submit"
            className="btn w-100 fw-bold"
            style={{
              fontSize: '1.08rem',
              background: '#2563eb',
              color: '#fff',
              border: 'none',
              borderRadius: 8,
              marginTop: 8,
              marginBottom: 8,
              boxShadow: '0 2px 8px rgba(37,99,235,0.10)',
              transition: 'background 0.2s'
            }}
            disabled={loading}
          >
            {loading ? (
              <span className="spinner-border spinner-border-sm" role="status" aria-hidden="true"></span>
            ) : (
              'Sign up'
            )}
          </button>
        </form>
        <div className="text-center mt-2" style={{ fontSize: '0.98rem', color: '#444' }}>
          Already have an account?{' '}
          <span
            className="fw-bold"
            style={{ color: '#2563eb', cursor: 'pointer' }}
            onClick={() => navigate('/login')}
          >
            Log in now
          </span>
        </div>
      </div>
      {/* Google Fonts for Poppins */}
      <link href="https://fonts.googleapis.com/css2?family=Poppins:wght@400;600&family=Montserrat:wght@500&display=swap" rel="stylesheet" />
    </div>
  );
};

export default Register;
